import { isPlatformBrowser } from '@angular/common';
import { Directive, ElementRef, Input, OnDestroy, OnInit, PLATFORM_ID, Renderer2, inject } from '@angular/core';

type RevealVariant = 'up' | 'line' | 'image' | 'left' | 'right' | 'scale';

@Directive({
  selector: '[appRevealOnScroll]',
  standalone: true
})
export class RevealOnScrollDirective implements OnInit, OnDestroy {
  private readonly element = inject<ElementRef<HTMLElement>>(ElementRef);
  private readonly renderer = inject(Renderer2);
  private readonly platformId = inject(PLATFORM_ID);
  private observer: IntersectionObserver | null = null;

  @Input() revealDelay = 0;
  @Input() revealVariant: RevealVariant = 'up';

  ngOnInit(): void {
    const nativeElement = this.element.nativeElement;
    this.renderer.addClass(nativeElement, 'site-reveal');
    this.renderer.addClass(nativeElement, `site-reveal--${this.revealVariant}`);
    this.renderer.setStyle(nativeElement, '--reveal-delay', `${Math.max(0, this.revealDelay)}ms`);

    if (
      !isPlatformBrowser(this.platformId)
      || typeof IntersectionObserver === 'undefined'
      || window.matchMedia('(prefers-reduced-motion: reduce)').matches
    ) {
      this.renderer.addClass(nativeElement, 'site-reveal--visible');
      return;
    }

    this.observer = new IntersectionObserver(([entry]) => {
      if (!entry.isIntersecting) {
        return;
      }

      this.renderer.addClass(nativeElement, 'site-reveal--visible');
      this.observer?.disconnect();
      this.observer = null;
    }, {
      rootMargin: '0px 0px -10% 0px',
      threshold: 0.08
    });

    // IntersectionObserver uses the layout box, so the element remains observable
    // even while clip-path hides its painted content.
    this.observer.observe(nativeElement);
  }

  ngOnDestroy(): void {
    this.observer?.disconnect();
  }
}
